// Service Worker pour Le petit aquarium du Marais — support hors-ligne
// CACHE_VERSION est mis à jour par sync-fish.py quand les ressources changent
const CACHE_VERSION = "aquarium-170b0811";

// ASSETS_START — auto-generated by sync, do not edit manually
const ASSETS = [
  "./",
  "style.css",
  "aquarium.js",
  "manifest.json",
  "favicon.svg",
  "images/fish-abel--chase.png",
  "images/fish-abel--chase.webp",
  "images/fish-abel--coeur.png",
  "images/fish-abel--coeur.webp",
  "images/fish-abel--marcus.png",
  "images/fish-abel--marcus.webp",
  "images/fish-abel--paillette.png",
  "images/fish-abel--paillette.webp",
  "images/fish-abel--pauline.png",
  "images/fish-abel--pauline.webp",
  "images/fish-louis--grenouille.png",
  "images/fish-louis--grenouille.webp",
  "images/fish-louis--grognon.png",
  "images/fish-louis--grognon.webp",
  "images/fish-louis--némo.png",
  "images/fish-louis--némo.webp",
  "images/fish-louis--origami.png",
  "images/fish-louis--origami.webp",
  "images/fish-louis--saucisson.png",
  "images/fish-louis--saucisson.webp",
];
// ASSETS_END

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(CACHE_VERSION).then((cache) => cache.addAll(ASSETS))
  );
  self.skipWaiting();
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(
        keys
          .filter((key) => key !== CACHE_VERSION)
          .map((key) => caches.delete(key))
      )
    )
  );
  self.clients.claim();
});

self.addEventListener("fetch", (event) => {
  event.respondWith(
    caches.match(event.request).then((cached) => {
      // Réseau d'abord pour la navigation, cache d'abord pour les ressources
      if (event.request.mode === "navigate") {
        return fetch(event.request)
          .then((response) => {
            const clone = response.clone();
            caches.open(CACHE_VERSION).then((cache) => cache.put(event.request, clone));
            return response;
          })
          .catch(() => cached);
      }
      return cached || fetch(event.request).then((response) => {
        const clone = response.clone();
        caches.open(CACHE_VERSION).then((cache) => cache.put(event.request, clone));
        return response;
      });
    })
  );
});
